=== UNPATCHED CscRebootRenamepOpenKey (sub_1C004785C) — feature-staging gate ===
// At 0x1c00478a3:
0x1c00478a3: call    0x1c00088b4        ; returns feature-flag state
0x1c00478a8: test    eax, eax
0x1c00478aa: je      0x1c004797d        ; if FALSE -> no-SD path (owner defaults; DACL parent-inherited)

// NO-SD path at 0x1c004797d — builds OA with SecurityDescriptor=0:
0x1c004797d: mov     dword [rbp-0x30], 0x30  ; Length
0x1c0047984: xorps   xmm0, xmm0
0x1c0047987: mov     qword [rbp-0x28], r12   ; RootDirectory = 0
0x1c004799f: mov     rcx, rsi
0x1c00479a2: movdqu  xmmword [rbp-0x10], xmm0 ; SD=0, SQOS=0 (NULL)
// ... then if arg3(create)!=0:
0x1c00479c2: call    qword [rel 0x1c0041338] ; ZwCreateKey(handle, KEY_ALL_ACCESS, &OA, 0, NULL, 0, &disp) — SecurityDescriptor = NULL

=== PATCHED CscRebootRenamepOpenKey (sub_1C004785C) — fixed (always SD on create) ===
// Gate removed; now purely on arg3:
0x1c0047898: test    r8b, r8b           ; create flag
0x1c004789b: je      0x1c0047912        ; if !create -> ZwOpenKey
// create -> ALWAYS build SD:
0x1c00478a1: call    0x1c00454b0        ; CscRebootRenamepCreateSecurityDescriptor (sub_1C00454B0) builds LocalSystem-owner SD
0x1c00478b6: mov     rdi, qword [rbp+0x20] ; rdi = SD pointer
0x1c00478f0: mov     qword [rbp-0x10], rdi  ; OA.SecurityDescriptor = SD
0x1c00478f4: call    qword [rel 0x1c0041338] ; ZwCreateKey WITH SD

=== CscRebootRenamepCreateSecurityDescriptor (sub_1C00454B0) (SD builder — sets OWNER only, no DACL; identical in both builds) ===
// Absolute security descriptor; DACL is never constructed:
PSID Sid = *(*SeExports + 0x108);  // SeLocalSystemSid
PSECURITY_DESCRIPTOR sd = ExAllocatePool2(POOL_FLAG_NON_PAGED, RtlLengthSid(Sid)+0x28, 'CrsR');
RtlCreateSecurityDescriptor(sd, SECURITY_DESCRIPTOR_REVISION);
Owner = sd + RtlLengthSecurityDescriptor(sd);
memmove(Owner, Sid, RtlLengthSid(Sid));
RtlSetOwnerSecurityDescriptor(sd, Owner, FALSE);  // OWNER only; no RtlSetDaclSecurityDescriptor
